package cell

import (
	"bytes"
	"crypto/sha256"
	"encoding/base64"
	"encoding/hex"
	"encoding/json"
	"hash/crc32"
	"testing"
)

type bocReferenceFixture struct {
	Block struct {
		FileHashHex string `json:"file_hash_hex"`
	} `json:"block"`

	RawBOCBase64      string `json:"raw_boc_base64"`
	ParsedRootHashHex string `json:"parsed_root_hash_hex"`
	SHA256RawBOCHex   string `json:"sha256_raw_boc_hex"`
}

const masterchainBlockFixtureJSON = `
{
  "network": "mainnet",
  "source": "liteServer.getBlock",
  "generated_at": "2026-03-20T11:49:49Z",
  "block": {
    "workchain": -1,
    "shard": "8000000000000000",
    "seqno": 58508098,
    "root_hash_hex": "8d6c098681215a9577c2b6695d0ae42b296dc47b47034f1750a2b20fcab10b83",
    "file_hash_hex": "b8bb78ae2b0bb6c855a83f31c746a244dd249235357d5fc3ce3d0b49ae07ebdc"
  },
  "raw_boc_len": 10655,
  "raw_boc_base64": "" ,
  "sha256_raw_boc_hex": "b8bb78ae2b0bb6c855a83f31c746a244dd249235357d5fc3ce3d0b49ae07ebdc",
  "parsed_root_hash_hex": "8d6c098681215a9577c2b6695d0ae42b296dc47b47034f1750a2b20fcab10b83",
  "sha256_matches_file_hash": true,
  "parsed_matches_root_hash": true
}
`

func loadBOCReferenceFixture(tb testing.TB) bocReferenceFixture {
	tb.Helper()

	data := []byte(masterchainBlockFixtureJSON)

	var fixture bocReferenceFixture
	if err := json.Unmarshal(data, &fixture); err != nil {
		tb.Fatalf("failed to decode embedded masterchain block fixture: %v", err)
	}

	return fixture
}

func TestToBOCWithOptions_Mode31_ReferenceFixture(t *testing.T) {
	fixture := loadBOCReferenceFixture(t)

	rawBOC, err := base64.StdEncoding.DecodeString(fixture.RawBOCBase64)
	if err != nil {
		t.Fatalf("failed to decode raw boc: %v", err)
	}

	root, err := FromBOC(rawBOC)
	if err != nil {
		t.Fatalf("failed to parse raw boc: %v", err)
	}

	if got := hex.EncodeToString(root.Hash()); got != fixture.ParsedRootHashHex {
		t.Fatalf("unexpected root hash, got %s want %s", got, fixture.ParsedRootHashHex)
	}

	gotBOC := root.ToBOCWithOptions(BOCOptions{
		WithCRC32C:    true,
		WithIndex:     true,
		WithCacheBits: true,
		WithTopHash:   true,
		WithIntHashes: true,
	})
	if len(gotBOC) == 0 {
		t.Fatal("expected non-empty canonical mode=31 boc")
	}

	parsed, err := FromBOC(gotBOC)
	if err != nil {
		t.Fatalf("failed to parse canonical mode=31 boc: %v", err)
	}
	if !bytes.Equal(parsed.Hash(), root.Hash()) {
		t.Fatalf("canonical mode=31 roundtrip hash mismatch, got %x want %x", parsed.Hash(), root.Hash())
	}

	wantSHA := sha256.Sum256(gotBOC)
	if got := ComputeFileHash(root); !bytes.Equal(got, wantSHA[:]) {
		t.Fatalf("unexpected canonical file hash, got %x want %x", got, wantSHA[:])
	}
}

func TestToBOCWithOptions_Mode3_CanonicalizedLegacyDictFixture(t *testing.T) {
	const legacyDictBOCHex = ""
	const expectedSHA256Hex = "2471ec52b476a8b09fc1694dc6539b1c481d8715db2f65f9bc318926f03958ff"

	legacyBOC, err := hex.DecodeString(legacyDictBOCHex)
	if err != nil {
		t.Fatalf("failed to decode dict fixture: %v", err)
	}

	// The historical fixture has a non-canonical ordinary level mask in the root descriptor.
	legacyBOC[12] = 0x03
	crc := crc32.Checksum(legacyBOC[:len(legacyBOC)-4], crc32.MakeTable(crc32.Castagnoli))
	legacyBOC[len(legacyBOC)-4] = byte(crc)
	legacyBOC[len(legacyBOC)-3] = byte(crc >> 8)
	legacyBOC[len(legacyBOC)-2] = byte(crc >> 16)
	legacyBOC[len(legacyBOC)-1] = byte(crc >> 24)

	root, err := FromBOC(legacyBOC)
	if err != nil {
		t.Fatalf("failed to parse canonicalized dict fixture: %v", err)
	}

	gotBOC := root.ToBOCWithOptions(BOCOptions{
		WithIndex:  true,
		WithCRC32C: true,
	})

	gotSHA := sha256.Sum256(gotBOC)
	if got := hex.EncodeToString(gotSHA[:]); got != expectedSHA256Hex {
		t.Fatalf("unexpected canonical mode=3 boc sha256, got %s want %s", got, expectedSHA256Hex)
	}
}

func TestToBOCWithOptions_RoundTripWithHashes(t *testing.T) {
	leaf := BeginCell().MustStoreUInt(0xABCD, 16).EndCell()
	left := BeginCell().MustStoreUInt(0x12, 8).MustStoreRef(leaf).EndCell()
	right := BeginCell().MustStoreUInt(0x34, 8).MustStoreRef(leaf).EndCell()
	root := BeginCell().
		MustStoreUInt(0x99, 8).
		MustStoreRef(left).
		MustStoreRef(right).
		MustStoreRef(leaf).
		EndCell()

	opts := BOCOptions{
		WithCRC32C:    true,
		WithIndex:     true,
		WithCacheBits: true,
		WithTopHash:   true,
		WithIntHashes: true,
	}

	boc := root.ToBOCWithOptions(opts)
	if len(boc) == 0 {
		t.Fatal("expected non-empty boc")
	}

	parsed, err := FromBOC(boc)
	if err != nil {
		t.Fatalf("failed to parse hash-aware boc: %v", err)
	}

	if !bytes.Equal(parsed.Hash(), root.Hash()) {
		t.Fatalf("roundtrip hash mismatch, got %x want %x", parsed.Hash(), root.Hash())
	}

	boc2 := parsed.ToBOCWithOptions(opts)
	if !bytes.Equal(boc, boc2) {
		t.Fatal("hash-aware boc roundtrip is not stable")
	}
}

func TestToBOCWithFlags_MatchesToBOCWithOptions(t *testing.T) {
	leaf := BeginCell().MustStoreUInt(0xABCD, 16).EndCell()
	root := BeginCell().
		MustStoreUInt(0x99, 8).
		MustStoreRef(leaf).
		EndCell()

	got := root.ToBOCWithFlags(true, true, true, true, true)
	want := root.ToBOCWithOptions(BOCOptions{
		WithCRC32C:    true,
		WithIndex:     true,
		WithCacheBits: true,
		WithTopHash:   true,
		WithIntHashes: true,
	})

	if !bytes.Equal(got, want) {
		t.Fatal("legacy ToBOCWithFlags output diverges from ToBOCWithOptions")
	}
}
